#include<bits/stdc++.h>
using namespace std;
int n,m,c[3030];
vector<int> mp[3030];
int dp[3030][3030],cnt,id[3030],siz[3030];
void dfs(int x)
{
    siz[x]=1;
    for(int i:mp[x])
    {
        dfs(i);
        siz[x]+=siz[i];
    }
    id[++cnt]=x;
}
int main()
{
    scanf("%d%d",&n,&m);
    for(int i=1;i<=n-m;i++)
    {
        int k;
        scanf("%d",&k);
        for(int j=1;j<=k;j++)
        {
            int x;
            scanf("%d",&x);
            scanf("%d",&c[x]);
            c[x]=-c[x];
            mp[i].push_back(x);
        }
    }
    for(int i=n-m+1;i<=n;i++)
    {
        int x;
        scanf("%d",&x);
        c[i]+=x;
    }
    dfs(1);
    memset(dp,-0x3f,sizeof(dp));
    for(int i=0;i<=cnt;i++)
    {
        dp[i][0]=0;
    }
    for(int i=1;i<=cnt;i++)
    {
        int x=id[i];
        for(int j=1;j<=m;j++)
        {
            if(x>=n-m+1)
            {
                dp[i][j]=max(dp[i-1][j-1]+c[x],dp[i-1][j]);
            }
            else
            {
                dp[i][j]=max(dp[i-1][j]+c[x],dp[i-siz[x]][j]);
            }
        }
    }
    for(int i=m;i>=0;i--)
    {
        if(dp[cnt][i]>=0)
        {
            printf("%d",i);
            return 0;
        }
    }
    return 0;
}
